module RefModule(
  input wire clk,
  input wire reset,
  output wire [31:0] count
);

  reg [31:0] obf_count_reg;

  always @(posedge clk) begin
    if (reset) begin
      obf_count_reg <= 0;
    end else begin
      obf_count_reg <= obf_count_reg + 1;
    end
  end

  assign count = obf_count_reg;

endmodule
